// ── GOOGLE FONTS + ENTERPRISE DESIGN SYSTEM ───────────────────────
const _fontLink = (() => {
  if(typeof document !== "undefined") {
    const l = document.createElement("link");
    l.rel = "stylesheet";
    l.href = "https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:ital,wght@0,300;0,400;0,500;0,600;0,700;0,800;1,400&family=JetBrains+Mono:wght@400;500;600&display=swap";
    document.head.appendChild(l);
    // Inject global styles
    const s = document.createElement("style");
    s.textContent = `
      :root {
        --brand:       #2563eb;
        --brand-deep:  #1d4ed8;
        --brand-light: #eff6ff;
        --brand-glow:  rgba(37,99,235,.22);
        --accent:      #06b6d4;
        --surface:     #ffffff;
        --surface-2:   #f8fafc;
        --surface-3:   #f1f5f9;
        --border:      #e2e8f0;
        --border-2:    #cbd5e1;
        --text-1:      #0f172a;
        --text-2:      #334155;
        --text-3:      #64748b;
        --text-4:      #94a3b8;
        --sidebar-bg:  #0f172a;
        --sidebar-w:   240px;
        --radius-sm:   6px;
        --radius-md:   10px;
        --radius-lg:   14px;
        --radius-xl:   18px;
        --shadow-sm:   0 1px 2px rgba(15,23,42,.05);
        --shadow-md:   0 2px 8px rgba(15,23,42,.08), 0 1px 2px rgba(15,23,42,.04);
        --shadow-lg:   0 8px 24px rgba(15,23,42,.10), 0 2px 6px rgba(15,23,42,.06);
        --shadow-xl:   0 20px 48px rgba(15,23,42,.14), 0 4px 12px rgba(15,23,42,.08);
        --font-sans:   'Plus Jakarta Sans', system-ui, sans-serif;
        --font-mono:   'JetBrains Mono', monospace;
      }
      *, *::before, *::after { box-sizing: border-box; }
      html, body, #root { height: 100%; margin: 0; }
      body { font-family: var(--font-sans); background: #f1f5f9; color: var(--text-1); -webkit-font-smoothing: antialiased; -moz-osx-font-smoothing: grayscale; }
      ::-webkit-scrollbar { width: 5px; height: 5px; }
      ::-webkit-scrollbar-track { background: transparent; }
      ::-webkit-scrollbar-thumb { background: var(--border-2); border-radius: 10px; }
      ::-webkit-scrollbar-thumb:hover { background: var(--text-4); }

      @keyframes fadeSlideIn { from { opacity:0; transform:translateY(10px); } to { opacity:1; transform:translateY(0); } }
      @keyframes fadeSlideUp { from { opacity:0; transform:translateY(16px); } to { opacity:1; transform:translateY(0); } }
      @keyframes fadeIn      { from { opacity:0; } to { opacity:1; } }
      @keyframes shimmer     { 0%,100% { opacity:.55; } 50% { opacity:1; } }
      @keyframes toastIn     { from { opacity:0; transform:translateX(110%) scale(.92); } to { opacity:1; transform:translateX(0) scale(1); } }
      @keyframes toastOut    { to   { opacity:0; transform:translateX(112%) scale(.92); } }
      @keyframes pulse       { 0%,100% { transform:scale(1); opacity:.7; } 50% { transform:scale(1.05); opacity:1; } }
      @keyframes barGrow     { from { width:0; } to { width:var(--w); } }
      @keyframes orb         { 0%,100% { transform:translate(0,0) scale(1); } 33% { transform:translate(40px,-30px) scale(1.08); } 66% { transform:translate(-20px,20px) scale(.94); } }
      @keyframes spin        { to { transform:rotate(360deg); } }
      @keyframes navPop      { from { opacity:0; transform:translateX(-6px); } to { opacity:1; transform:translateX(0); } }

      .page-enter  { animation: fadeSlideIn .3s cubic-bezier(.22,1,.36,1) both; }
      .card-hover  { transition: transform .22s cubic-bezier(.22,1,.36,1), box-shadow .22s ease; }
      .card-hover:hover { transform: translateY(-2px); box-shadow: var(--shadow-lg) !important; }
      .row-hover:hover  { background: #f5f8ff !important; }

      .btn-primary { transition: filter .15s, transform .13s, box-shadow .15s; }
      .btn-primary:hover  { filter: brightness(1.07); transform: translateY(-1px); box-shadow: 0 8px 20px var(--brand-glow) !important; }
      .btn-primary:active { transform: translateY(0); filter: brightness(.97); }

      .nav-item { transition: all .15s cubic-bezier(.22,1,.36,1); }
      .nav-item:hover { background: rgba(255,255,255,.08) !important; color: #fff !important; }

      .nav-active-item { animation: navPop .2s cubic-bezier(.22,1,.36,1) both; }

      input:focus, select:focus, textarea:focus {
        outline: none !important;
        border-color: var(--brand) !important;
        box-shadow: 0 0 0 3px var(--brand-glow) !important;
      }

      /* Table row hover */
      .trow-hover { transition: background .1s; }
      .trow-hover:hover td { background: var(--brand-light) !important; }

      /* KPI card hover */
      .kpi-card:hover { transform: translateY(-3px) !important; }

      /* Status dot pulse */
      .status-online { animation: statusPulse 2.5s ease-in-out infinite; }
      @keyframes statusPulse { 0%,100% { box-shadow: 0 0 0 0 rgba(34,197,94,.4); } 50% { box-shadow: 0 0 0 5px rgba(34,197,94,0); } }

      /* Toast enter/exit */
      .toast-enter { animation: toastIn .3s cubic-bezier(.22,1,.36,1) both; }
      .toast-exit  { animation: toastOut .25s ease forwards; }

      /* Smooth page transitions */
      .page-enter { animation: fadeSlideIn .28s cubic-bezier(.22,1,.36,1) both; }

      /* Sidebar nav active item */
      .nav-active-bar { background: linear-gradient(180deg, var(--brand), var(--accent)); }

      /* Sidebar section label */
      .nav-sec-label {
        font-family: var(--font-mono);
        font-size: 9px;
        letter-spacing: 2px;
        text-transform: uppercase;
        color: rgba(255,255,255,.28);
        padding: 0 12px;
        margin-bottom: 2px;
        margin-top: 4px;
      }
      /* Thin divider */
      .nav-divider { height: 1px; background: rgba(255,255,255,.06); margin: 6px 10px; }

      /* Status dot pulse */
      @keyframes statusPulse { 0%,100%{box-shadow:0 0 0 0 rgba(34,197,94,.5)} 50%{box-shadow:0 0 0 5px rgba(34,197,94,0)} }
      .status-online { animation: statusPulse 2s ease infinite; }

      /* Chip hover */
      .chip-hover { transition: background .12s, transform .12s; cursor: pointer; }
      .chip-hover:hover { transform: scale(1.04); }

      /* KPI card gradient accent */
      .kpi-card { position: relative; overflow: hidden; }
      .kpi-card::before { content:''; position:absolute; top:-32px; right:-32px; width:100px; height:100px; border-radius:50%; opacity:.07; }

      /* Smooth modal backdrop */
      .modal-backdrop { animation: fadeIn .18s ease both; }
      .modal-content  { animation: fadeSlideUp .25s cubic-bezier(.22,1,.36,1) both; }

      /* Priority badge */
      .badge { display:inline-flex; align-items:center; gap:4px; padding:2px 9px; border-radius:20px; font-size:11px; font-weight:700; letter-spacing:.2px; white-space:nowrap; }

      /* ── Enhanced card interactions ── */
      .card-clickable {
        cursor: pointer;
        transition: transform .2s cubic-bezier(.22,1,.36,1), box-shadow .2s ease, border-color .15s;
      }
      .card-clickable:hover {
        transform: translateY(-2px);
        box-shadow: var(--shadow-lg) !important;
        border-color: var(--border-2) !important;
      }
      .card-clickable:active { transform: translateY(0); }

      /* ── Page hero gradient banners ── */
      .page-hero {
        border-radius: var(--radius-xl);
        padding: 22px 28px;
        margin-bottom: 20px;
        background: linear-gradient(135deg, #0f172a 0%, #1e3a6e 55%, var(--brand) 100%);
        position: relative;
        overflow: hidden;
      }
      .page-hero::before {
        content: '';
        position: absolute;
        inset: 0;
        background-image: linear-gradient(rgba(255,255,255,.03) 1px, transparent 1px),
                          linear-gradient(90deg, rgba(255,255,255,.03) 1px, transparent 1px);
        background-size: 32px 32px;
        pointer-events: none;
      }
      .page-hero-title {
        font-size: 20px;
        font-weight: 800;
        color: #fff;
        letter-spacing: -.4px;
        margin: 0 0 4px;
      }
      .page-hero-sub {
        font-size: 12px;
        color: rgba(255,255,255,.6);
        margin: 0;
        font-family: var(--font-mono);
      }

      /* ── Stat ring glow ── */
      .stat-ring-glow { filter: drop-shadow(0 0 6px currentColor); opacity: .7; }

      /* ── Gradient text utility ── */
      .grad-text {
        background: linear-gradient(135deg, var(--brand), var(--accent));
        -webkit-background-clip: text;
        -webkit-text-fill-color: transparent;
        background-clip: text;
      }

      /* ── Improved table rows ── */
      .trow-hover:hover td {
        background: #f0f7ff !important;
        cursor: pointer;
      }

      /* ── Section divider with label ── */
      .section-divider {
        display: flex;
        align-items: center;
        gap: 10px;
        margin: 18px 0 12px;
        font-size: 10px;
        font-weight: 700;
        color: var(--text-4);
        text-transform: uppercase;
        letter-spacing: 1.4px;
        font-family: var(--font-mono);
      }
      .section-divider::before, .section-divider::after {
        content: '';
        flex: 1;
        height: 1px;
        background: var(--border);
      }

      /* ── Improved scrollbar for tables ── */
      .table-wrap { overflow-x: auto; border-radius: var(--radius-lg); }
      .table-wrap::-webkit-scrollbar { height: 4px; }

      /* ── Sidebar nav section polish ── */
      .nav-item-active {
        background: linear-gradient(90deg, rgba(37,99,235,.25) 0%, rgba(37,99,235,.08) 100%) !important;
        border-left: 3px solid var(--brand) !important;
        color: #fff !important;
      }

      /* ── Flag severity badges ── */
      .sev-critical { background:#fef2f2; color:#dc2626; border:1px solid #fecaca; }
      .sev-high     { background:#fff7ed; color:#ea580c; border:1px solid #fed7aa; }
      .sev-medium   { background:#fffbeb; color:#d97706; border:1px solid #fde68a; }
      .sev-low      { background:#f0fdf4; color:#059669; border:1px solid #bbf7d0; }

      /* ── Heatmap cell ── */
      .heatmap-cell {
        border-radius: 4px;
        transition: transform .12s, opacity .12s;
        cursor: default;
      }
      .heatmap-cell:hover { transform: scale(1.25); opacity: 1 !important; z-index: 10; }

      /* ── Progress bar with shimmer ── */
      .prog-shimmer {
        position: relative;
        overflow: hidden;
      }
      .prog-shimmer::after {
        content: '';
        position: absolute;
        inset: 0;
        background: linear-gradient(90deg, transparent 0%, rgba(255,255,255,.25) 50%, transparent 100%);
        animation: shimmer 2s ease-in-out infinite;
      }

      /* ── Empty state ── */
      .empty-state {
        display: flex;
        flex-direction: column;
        align-items: center;
        justify-content: center;
        padding: 48px 24px;
        color: var(--text-4);
        text-align: center;
      }
      .empty-state-icon { font-size: 40px; margin-bottom: 12px; opacity: .6; }
      .empty-state-title { font-size: 15px; font-weight: 700; color: var(--text-2); margin-bottom: 6px; }
      .empty-state-sub { font-size: 12px; line-height: 1.6; max-width: 280px; }

      /* ── Tooltip-style hint ── */
      [data-hint] { position: relative; }
      [data-hint]:hover::after {
        content: attr(data-hint);
        position: absolute;
        bottom: calc(100% + 6px);
        left: 50%;
        transform: translateX(-50%);
        background: #1e293b;
        color: #fff;
        font-size: 10px;
        padding: 4px 8px;
        border-radius: 5px;
        white-space: nowrap;
        pointer-events: none;
        z-index: 100;
      }
    `;
    document.head.appendChild(s);
  }
})();

