  // ── Build nav from registry ──────────────────────────────────────────
  // Helper: collect unique sections for a given side (mgr/mbr) preserving order
  function buildNav(side) {
    const secOrder = [];
    const secMap   = {};
    FEATURE_REGISTRY.forEach(f => {
      const secKey = side === "mgr" ? f.mgrSec : f.mbrSec;
      if (!secKey) return; // not in this nav
      // Role filter: "admin" entries only appear for admin users
      if (f.role === "admin" && !isAdmin) return;
      if (!secMap[secKey]) { secMap[secKey] = []; secOrder.push(secKey); }
      secMap[secKey].push({
        id:    f.id,
        icon:  f.icon,
        label: side === "mgr" ? (f.mgrLabel || f.label) : (f.mbrLabel || f.label),
      });
    });
    return secOrder.map(sec => ({ sec, items: secMap[sec] }));
  }

  const NAV_MGR = buildNav("mgr");
  const NAV_MBR = buildNav("mbr");
  const NAV = isMgrOrAdmin ? NAV_MGR : NAV_MBR;

